document.addEventListener('DOMContentLoaded', () => {
    // DOM Elements - Editor
    const canvas = document.getElementById('editor-canvas');
    const ctx = canvas.getContext('2d');
    const canvasContainer = document.getElementById('canvas-container');
    const fileInput = document.getElementById('file-input');
    const dropZone = document.getElementById('drop-zone');
    const adjustmentControls = document.getElementById('adjustment-controls');
    const dragInstruction = document.getElementById('drag-instruction');

    // Sliders & Editor Controls
    const sliderZoom = document.getElementById('slider-zoom');
    const sliderRotate = document.getElementById('slider-rotate');
    const valueZoom = document.getElementById('value-zoom');
    const valueRotate = document.getElementById('value-rotate');
    const btnFit = document.getElementById('btn-fit');
    const btnReset = document.getElementById('btn-reset');

    // Action Buttons
    const btnSaveDraft = document.getElementById('btn-save-draft');
    const btnShare = document.getElementById('btn-share');
    const btnCamera = document.getElementById('btn-camera');
    const toast = document.getElementById('toast-message');

    // Camera Modal Elements
    const cameraModal = document.getElementById('camera-modal');
    const cameraStream = document.getElementById('camera-stream');
    const btnCapture = document.getElementById('btn-capture');
    const btnCancelCamera = document.getElementById('btn-cancel-camera');

    // Share Modal Elements
    const shareModal = document.getElementById('share-modal');
    const qrLoading = document.getElementById('qr-loading');
    const qrContainer = document.getElementById('qr-container');
    const qrImage = document.getElementById('qr-image');
    const btnDownloadFallback = document.getElementById('btn-download-fallback');
    const btnCloseShare = document.getElementById('btn-close-share');

    // Drafts Elements
    const draftsCard = document.getElementById('drafts-card');
    const draftsPlaceholder = document.getElementById('drafts-placeholder');
    const draftsContainer = document.getElementById('drafts-container');
    const btnZipDrafts = document.getElementById('btn-zip-drafts');

    // Confetti canvas setup
    const confettiCanvas = document.getElementById('confetti-canvas');
    const confettiCtx = confettiCanvas.getContext('2d');

    // State Variables
    let frameImage = new Image();
    let userImage = null;
    let cameraStreamTrack = null;
    let drafts = []; // Array of saved composite data URLs

    // Share modal state
    let shareMode = 'single'; // 'single' or 'zip'
    let activeShareImageURL = null; // Data URL for single photo
    let zipBlobData = null; // Blob for zip archive

    // Image Transformations
    let posX = 0;
    let posY = 0;
    let baseScale = 1.0;
    let userScale = 1.0;
    let rotation = 0;

    // Canvas size
    let canvasWidth = 1080;
    let canvasHeight = 1080;

    // Pointer events state for dragging
    let isDragging = false;
    let startX = 0;
    let startY = 0;

    // Load Frame Image from directory
    frameImage.onload = () => {
        canvasWidth = frameImage.naturalWidth || 1080;
        canvasHeight = frameImage.naturalHeight || 1080;
        canvas.width = canvasWidth;
        canvas.height = canvasHeight;
        draw();
    };
    frameImage.onerror = () => {
        showToast('Gagal memuat Frame.png. Pastikan file ada di folder image/');
    };
    frameImage.src = 'data:image/png;base64,';

    // Main Draw Function
    function draw() {
        ctx.fillStyle = '#ffffff';
        ctx.fillRect(0, 0, canvasWidth, canvasHeight);

        // 1. Draw User Image behind frame
        if (userImage) {
            ctx.save();
            ctx.translate(canvasWidth / 2 + posX, canvasHeight / 2 + posY);
            ctx.rotate((rotation * Math.PI) / 180);

            const finalScale = baseScale * userScale;
            ctx.scale(finalScale, finalScale);

            ctx.drawImage(
                userImage,
                -userImage.naturalWidth / 2,
                -userImage.naturalHeight / 2,
                userImage.naturalWidth,
                userImage.naturalHeight
            );
            ctx.restore();
        } else {
            // Draw placeholder background
            ctx.save();
            ctx.fillStyle = '#f8fafc';
            ctx.fillRect(0, 0, canvasWidth, canvasHeight);

            ctx.fillStyle = '#cbd5e1';
            for (let i = 40; i < canvasWidth; i += 40) {
                for (let j = 40; j < canvasHeight; j += 40) {
                    ctx.beginPath();
                    ctx.arc(i, j, 1.5, 0, Math.PI * 2);
                    ctx.fill();
                }
            }
            ctx.restore();
        }

        // 2. Draw Frame Image on top
        ctx.drawImage(frameImage, 0, 0, canvasWidth, canvasHeight);
    }

    // Auto-crop / Fit calculation (Cover logic)
    function calculateAutoFit() {
        if (!userImage) return;

        const canvasAspect = canvasWidth / canvasHeight;
        const imgAspect = userImage.naturalWidth / userImage.naturalHeight;

        if (imgAspect > canvasAspect) {
            baseScale = canvasHeight / userImage.naturalHeight;
        } else {
            baseScale = canvasWidth / userImage.naturalWidth;
        }

        posX = 0;
        posY = 0;
        userScale = 1.0;
        rotation = 0;

        sliderZoom.value = 100;
        sliderRotate.value = 0;
        valueZoom.textContent = '100%';
        valueRotate.textContent = '0°';
    }

    // Handle Uploaded File
    function handleImageFile(file) {
        if (!file || !file.type.startsWith('image/')) {
            showToast('Format berkas tidak didukung. Unggah gambar!');
            return;
        }

        const reader = new FileReader();
        reader.onload = (e) => {
            const img = new Image();
            img.onload = () => {
                userImage = img;
                activateControls();
                calculateAutoFit();
                draw();
                showToast('Foto berhasil dimuat! Anda dapat menggeser langsung.');
            };
            img.src = e.target.result;
        };
        reader.readAsDataURL(file);
    }

    function activateControls() {
        adjustmentControls.classList.add('active');
        dragInstruction.style.display = 'flex';
        btnSaveDraft.removeAttribute('disabled');
        btnShare.removeAttribute('disabled');
    }

    // File Input change
    fileInput.addEventListener('change', (e) => {
        if (e.target.files.length > 0) {
            handleImageFile(e.target.files[0]);
        }
    });

    // Drag and Drop
    dropZone.addEventListener('click', () => fileInput.click());

    dropZone.addEventListener('dragover', (e) => {
        e.preventDefault();
        dropZone.classList.add('dragover');
    });

    ['dragleave', 'dragend'].forEach(eventName => {
        dropZone.addEventListener(eventName, () => {
            dropZone.classList.remove('dragover');
        });
    });

    dropZone.addEventListener('drop', (e) => {
        e.preventDefault();
        dropZone.classList.remove('dragover');
        if (e.dataTransfer.files.length > 0) {
            handleImageFile(e.dataTransfer.files[0]);
        }
    });

    // Sliders & Reset Event Listeners
    sliderZoom.addEventListener('input', (e) => {
        userScale = parseFloat(e.target.value) / 100;
        valueZoom.textContent = `${e.target.value}%`;
        draw();
    });

    sliderRotate.addEventListener('input', (e) => {
        rotation = parseInt(e.target.value);
        valueRotate.textContent = `${e.target.value}°`;
        draw();
    });

    btnFit.addEventListener('click', () => {
        if (!userImage) return;
        calculateAutoFit();
        draw();
        showToast('Foto dipaskan ke ukuran bingkai');
    });

    btnReset.addEventListener('click', () => {
        if (!userImage) return;
        calculateAutoFit();
        draw();
        showToast('Pengaturan di-reset');
    });

    // Pointer-events dragging directly on canvas
    canvasContainer.addEventListener('pointerdown', (e) => {
        if (!userImage) return;
        isDragging = true;
        startX = e.clientX;
        startY = e.clientY;
        canvasContainer.setPointerCapture(e.pointerId);
    });

    canvasContainer.addEventListener('pointermove', (e) => {
        if (!isDragging || !userImage) return;

        const dx = e.clientX - startX;
        const dy = e.clientY - startY;

        const rect = canvas.getBoundingClientRect();
        const scaleX = canvasWidth / rect.width;
        const scaleY = canvasHeight / rect.height;

        posX += dx * scaleX;
        posY += dy * scaleY;

        startX = e.clientX;
        startY = e.clientY;

        draw();
    });

    const stopDragging = (e) => {
        if (isDragging) {
            isDragging = false;
            try {
                canvasContainer.releasePointerCapture(e.pointerId);
            } catch (err) { }
        }
    };

    canvasContainer.addEventListener('pointerup', stopDragging);
    canvasContainer.addEventListener('pointercancel', stopDragging);

    // ==========================================
    // CAMERA STREAM CAPTURE
    // ==========================================
    btnCamera.addEventListener('click', async () => {
        try {
            const stream = await navigator.mediaDevices.getUserMedia({
                video: { width: 1280, height: 720, facingMode: "user" },
                audio: false
            });
            cameraStream.srcObject = stream;
            cameraStreamTrack = stream.getVideoTracks()[0];
            cameraModal.classList.add('active');
        } catch (err) {
            console.error("Camera access error:", err);
            showToast('Gagal mengakses kamera. Periksa izin perangkat Anda.');
        }
    });

    function closeCamera() {
        if (cameraStreamTrack) {
            cameraStreamTrack.stop();
            cameraStreamTrack = null;
        }
        cameraStream.srcObject = null;
        cameraModal.classList.remove('active');
    }

    btnCancelCamera.addEventListener('click', closeCamera);

    btnCapture.addEventListener('click', () => {
        if (!cameraStream.srcObject) return;

        // Capture canvas mirroring back horizontally
        const tempCanvas = document.createElement('canvas');
        tempCanvas.width = cameraStream.videoWidth || 640;
        tempCanvas.height = cameraStream.videoHeight || 480;
        const tempCtx = tempCanvas.getContext('2d');

        tempCtx.translate(tempCanvas.width, 0);
        tempCtx.scale(-1, 1);
        tempCtx.drawImage(cameraStream, 0, 0, tempCanvas.width, tempCanvas.height);

        const img = new Image();
        img.onload = () => {
            userImage = img;
            activateControls();
            calculateAutoFit();
            draw();
            closeCamera();
            showToast('Foto kamera berhasil diambil!');
        };
        img.src = tempCanvas.toDataURL('image/png');
    });

    // ==========================================
    // DRAFTS SYSTEM
    // ==========================================
    btnSaveDraft.addEventListener('click', () => {
        if (!userImage) return;

        const dataUrl = canvas.toDataURL('image/png');
        drafts.push(dataUrl);
        updateDraftsUI();
        showToast('Foto berhasil ditambahkan ke draf!');
    });

    function updateDraftsUI() {
        if (drafts.length === 0) {
            draftsPlaceholder.style.display = 'block';
            draftsContainer.style.display = 'none';
            btnZipDrafts.style.display = 'none';
            return;
        }

        draftsPlaceholder.style.display = 'none';
        draftsContainer.style.display = 'grid';
        draftsContainer.innerHTML = '';

        // Show ZIP button only if there are 2 or more drafts
        if (drafts.length >= 2) {
            btnZipDrafts.style.display = 'inline-flex';
        } else {
            btnZipDrafts.style.display = 'none';
        }

        drafts.forEach((draftData, idx) => {
            const item = document.createElement('div');
            item.className = 'draft-item';

            const img = document.createElement('img');
            img.src = draftData;
            img.alt = `Draf Foto ${idx + 1}`;

            const overlay = document.createElement('div');
            overlay.className = 'draft-overlay';

            const btnOpenShare = document.createElement('button');
            btnOpenShare.className = 'draft-btn draft-btn-download';
            btnOpenShare.innerHTML = `
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5">
                    <circle cx="18" cy="5" r="3"></circle>
                    <circle cx="6" cy="12" r="3"></circle>
                    <circle cx="18" cy="19" r="3"></circle>
                    <line x1="8.59" y1="13.51" x2="15.42" y2="17.49"></line>
                </svg> Bagikan / Unduh
            `;
            btnOpenShare.addEventListener('click', () => {
                openShareModal(draftData, false);
            });

            const btnDel = document.createElement('button');
            btnDel.className = 'draft-btn draft-btn-delete';
            btnDel.innerHTML = `
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5">
                    <polyline points="3 6 5 6 21 6"></polyline>
                    <path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path>
                </svg> Hapus
            `;
            btnDel.addEventListener('click', () => {
                drafts.splice(idx, 1);
                updateDraftsUI();
                showToast('Draf dihapus');
            });

            overlay.appendChild(btnOpenShare);
            overlay.appendChild(btnDel);
            item.appendChild(img);
            item.appendChild(overlay);
            draftsContainer.appendChild(item);
        });
    }

    // Compile all drafts to a ZIP and open share modal
    btnZipDrafts.addEventListener('click', async () => {
        if (drafts.length === 0) return;

        showToast('Mengompres draf foto ke file ZIP...');

        try {
            const zip = new JSZip();
            drafts.forEach((draftData, idx) => {
                const base64Data = draftData.split(',')[1];
                zip.file(`Hanari_Photo_${idx + 1}.png`, base64Data, { base64: true });
            });

            const zipBlob = await zip.generateAsync({ type: "blob" });
            openShareModal(zipBlob, true);
        } catch (err) {
            console.error("ZIP packaging error:", err);
            showToast('Gagal mengompres draf foto.');
        }
    });

    // ==========================================
    // SHARE / DOWNLOAD MODAL (QR & EMAIL)
    // ==========================================
    btnShare.addEventListener('click', () => {
        if (!userImage) return;
        const currentDataUrl = canvas.toDataURL('image/png');
        openShareModal(currentDataUrl, false);
    });

    async function openShareModal(dataOrBlob, isZip = false) {
        // Configure modal details based on mode
        if (isZip) {
            shareMode = 'zip';
            zipBlobData = dataOrBlob;
            activeShareImageURL = null;
            document.querySelector('.share-card .modal-title').innerHTML = 'Unduh Semua Draf (ZIP) 📦';
            btnDownloadFallback.innerHTML = `
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" style="margin-right:0.25rem;">
                    <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"></path>
                    <polyline points="7 10 12 15 17 10"></polyline>
                    <line x1="12" y1="15" x2="12" y2="3"></line>
                </svg> Unduh File ZIP
            `;
        } else {
            shareMode = 'single';
            zipBlobData = null;
            activeShareImageURL = dataOrBlob;
            document.querySelector('.share-card .modal-title').innerHTML = 'Unduh & Bagikan Foto 📸';
            btnDownloadFallback.innerHTML = `
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" style="margin-right:0.25rem;">
                    <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"></path>
                    <polyline points="7 10 12 15 17 10"></polyline>
                    <line x1="12" y1="15" x2="12" y2="3"></line>
                </svg> Unduh Langsung (File PNG)
            `;
        }

        // Reset Share Modal state
        qrLoading.style.display = 'flex';
        qrContainer.style.display = 'none';
        qrImage.style.display = 'block';
        qrImage.src = '';

        shareModal.classList.add('active');

        try {
            // Upload to temporary hosting (handles either image dataURL or ZIP Blob)
            const directDownloadURL = await uploadToHost(dataOrBlob, isZip);

            // Generate QR Code pointing to direct download URL
            const qrAPIUrl = `https://api.qrserver.com/v1/create-qr-code/?size=180x180&data=${encodeURIComponent(directDownloadURL)}`;

            qrImage.onload = () => {
                qrLoading.style.display = 'none';
                qrContainer.style.display = 'block';
            };
            qrImage.src = qrAPIUrl;

        } catch (err) {
            console.error("Upload/QR error:", err);
            qrLoading.style.display = 'none';
            qrContainer.style.display = 'block';
            qrImage.style.display = 'none';
            showToast('Gagal memuat Kode QR. Anda masih bisa mengunduh file secara langsung.');
        }
    }

    // Helper to convert base64 data URL to Blob (highly reliable offline/local)
    function dataURLtoBlob(dataurl) {
        const arr = dataurl.split(',');
        const mime = arr[0].match(/:(.*?);/)[1];
        const bstr = atob(arr[1]);
        let n = bstr.length;
        const u8arr = new Uint8Array(n);
        while (n--) {
            u8arr[n] = bstr.charCodeAt(n);
        }
        return new Blob([u8arr], { type: mime });
    }

    // Helper to upload image/ZIP to temporary public hosting with automatic fallbacks
    async function uploadToHost(dataOrBlob, isZip) {
        let blob;
        let filename;

        if (isZip) {
            blob = dataOrBlob;
            filename = 'Hanari_Photos_Drafts.zip';
        } else {
            blob = dataURLtoBlob(dataOrBlob);
            filename = 'Hanari_Photo.png';
        }

        // Host 1: tmpfiles.org
        try {
            const formData = new FormData();
            formData.append('file', blob, filename);

            const uploadResponse = await fetch('https://tmpfiles.org/api/v1/upload', {
                method: 'POST',
                body: formData
            });

            if (uploadResponse.ok) {
                const resultJson = await uploadResponse.json();
                if (resultJson.status === 'success' && resultJson.data && resultJson.data.url) {
                    const viewURL = resultJson.data.url;
                    return viewURL.replace('https://tmpfiles.org/', 'https://tmpfiles.org/dl/');
                }
            }
        } catch (err) {
            console.warn("tmpfiles.org failed, trying uguu.se...", err);
        }

        // Host 2: uguu.se (Backup 1)
        try {
            const formData = new FormData();
            formData.append('files[]', blob, filename);

            const uploadResponse = await fetch('https://uguu.se/api.php?d=upload-tool', {
                method: 'POST',
                body: formData
            });

            if (uploadResponse.ok) {
                const resultJson = await uploadResponse.json();
                if (resultJson.success && resultJson.files && resultJson.files[0] && resultJson.files[0].url) {
                    return resultJson.files[0].url;
                }
            }
        } catch (err) {
            console.warn("uguu.se failed, trying file.io...", err);
        }

        // Host 3: file.io (Backup 2)
        try {
            const formData = new FormData();
            formData.append('file', blob, filename);

            const uploadResponse = await fetch('https://file.io', {
                method: 'POST',
                body: formData
            });

            if (uploadResponse.ok) {
                const resultJson = await uploadResponse.json();
                if (resultJson.success && resultJson.link) {
                    return resultJson.link;
                }
            }
        } catch (err) {
            console.warn("file.io failed...", err);
        }

        throw new Error('Semua hosting upload gagal');
    }

    // Fallback direct file download button
    btnDownloadFallback.addEventListener('click', () => {
        const dateStr = new Date().toISOString().slice(0, 10);
        const link = document.createElement('a');

        if (shareMode === 'single') {
            if (!activeShareImageURL) return;
            link.download = `Hanari_Photo_${dateStr}.png`;
            link.href = activeShareImageURL;
            link.click();
            showToast('Foto diunduh ke PC!');
            triggerConfetti();
        } else {
            if (!zipBlobData) return;
            link.download = `Hanari_Photos_${dateStr}.zip`;
            link.href = URL.createObjectURL(zipBlobData);
            link.click();
            showToast('File ZIP diunduh ke PC!');
            triggerConfetti();
        }
    });



    function closeShareModal() {
        shareModal.classList.remove('active');
        activeShareImageURL = null;
        zipBlobData = null;
    }

    btnCloseShare.addEventListener('click', closeShareModal);

    // ==========================================
    // TOAST ALERTS HELPER
    // ==========================================
    let toastTimeout;
    function showToast(message) {
        clearTimeout(toastTimeout);
        toast.textContent = message;
        toast.classList.add('show');
        toastTimeout = setTimeout(() => {
            toast.classList.remove('show');
        }, 3500);
    }

    // ==========================================
    // CONFETTI PHYSICS SYSTEM
    // ==========================================
    let confettiActive = false;
    let particles = [];
    const colors = ['#e53935', '#ffffff', '#ffc107', '#ff8a80', '#eceff1'];

    function resizeConfettiCanvas() {
        confettiCanvas.width = window.innerWidth;
        confettiCanvas.height = window.innerHeight;
    }
    window.addEventListener('resize', resizeConfettiCanvas);
    resizeConfettiCanvas();

    function triggerConfetti() {
        particles = [];
        resizeConfettiCanvas();

        for (let i = 0; i < 150; i++) {
            particles.push({
                x: window.innerWidth / 2,
                y: window.innerHeight + 20,
                radius: Math.random() * 4 + 4,
                color: colors[Math.floor(Math.random() * colors.length)],
                vx: (Math.random() - 0.5) * 20,
                vy: -Math.random() * 15 - 10,
                gravity: 0.4,
                rotation: Math.random() * 360,
                rotationSpeed: Math.random() * 10 - 5,
                opacity: 1
            });
        }

        if (!confettiActive) {
            confettiActive = true;
            updateConfetti();
        }
    }

    function updateConfetti() {
        if (particles.length === 0) {
            confettiActive = false;
            confettiCtx.clearRect(0, 0, confettiCanvas.width, confettiCanvas.height);
            return;
        }

        confettiCtx.clearRect(0, 0, confettiCanvas.width, confettiCanvas.height);

        particles.forEach((p, idx) => {
            p.vy += p.gravity;
            p.x += p.vx;
            p.y += p.vy;
            p.rotation += p.rotationSpeed;

            if (p.vy > 0) {
                p.opacity -= 0.01;
            }

            if (p.opacity <= 0 || p.y > window.innerHeight + 50 || p.x < -50 || p.x > window.innerWidth + 50) {
                particles.splice(idx, 1);
                return;
            }

            confettiCtx.save();
            confettiCtx.translate(p.x, p.y);
            confettiCtx.rotate((p.rotation * Math.PI) / 180);
            confettiCtx.globalAlpha = p.opacity;

            confettiCtx.fillStyle = p.color;
            confettiCtx.fillRect(-p.radius, -p.radius / 2, p.radius * 2, p.radius);

            confettiCtx.restore();
        });

        requestAnimationFrame(updateConfetti);
    }
});
